// Recolectar todos los datos de las hojas
const leads        = $('Leer Leads Master').all().map(i => i.json);
const demos        = $('Leer Demo Sessions').all().map(i => i.json);
const reservations = $('Leer Reservations Pipeline').all().map(i => i.json);
const testimonios  = $('Leer Testimonios').all().map(i => i.json);
const content      = $('Leer Content Calendar').all().map(i => i.json);

// ── FUNNEL ──────────────────────────────────────
const totalLeads        = leads.length;
const totalDemos        = demos.length;
const demosCompleted    = demos.filter(d => (d.Status || d.status || '').toLowerCase() === 'completed').length;
const totalReservations = reservations.length;
const paid              = reservations.filter(r => (r.Estado || r.status || '').toLowerCase() === 'paid').length;
const cancelled         = reservations.filter(r => (r.Estado || r.status || '').toLowerCase() === 'cancelled').length;
const noShow            = reservations.filter(r => (r.Estado || r.status || '').toLowerCase() === 'no_show').length;
const revenueUSD        = paid * 397;

// ── CONVERSIONES ────────────────────────────────
const leadToDemo        = totalLeads > 0  ? ((totalDemos / totalLeads) * 100).toFixed(1) + '%' : '0%';
const demoToReservation = totalDemos > 0  ? ((totalReservations / totalDemos) * 100).toFixed(1) + '%' : '0%';
const reservationToPaid = totalReservations > 0 ? ((paid / totalReservations) * 100).toFixed(1) + '%' : '0%';
const overallConversion = totalLeads > 0 ? ((paid / totalLeads) * 100).toFixed(1) + '%' : '0%';

// ── PIPELINE STATUS ─────────────────────────────
const pipeline = {
  new:       reservations.filter(r => (r.Estado || r.status || '').toLowerCase() === 'new').length,
  contacted: reservations.filter(r => (r.Estado || r.status || '').toLowerCase() === 'contacted').length,
  qualified: reservations.filter(r => (r.Estado || r.status || '').toLowerCase() === 'qualified').length,
  validated: reservations.filter(r => (r.Estado || r.status || '').toLowerCase() === 'validated').length,
  paid,
  cancelled,
  no_show: noShow
};

// ── AGENTES ─────────────────────────────────────
const agentNames = ['Sales AI Closer', 'AI Lead Engine', 'AI Support Agent', 'Marketing AI Agent', 'E-Commerce Agent', 'Appointment Setting Agent'];
const agents = agentNames.map(name => ({
  name,
  demos:        demos.filter(d => (d.Agente || d['Agent Name'] || d.agent_name || '').toLowerCase().includes(name.toLowerCase().split(' ')[0])).length,
  reservations: reservations.filter(r => (r.Agente || r.agent || '').toLowerCase().includes(name.toLowerCase().split(' ')[0])).length,
  testimonials: testimonios.filter(t => (t['Agente Usado'] || t.agente || '').toLowerCase().includes(name.toLowerCase().split(' ')[0])).length
}));

// ── TESTIMONIOS / NPS ────────────────────────────
const validTestimonios = testimonios.filter(t => {
  const score = parseInt(t['Calificación (1-5)'] || t.calificacion || t.score || 0);
  return score > 0;
});
const avgRating = validTestimonios.length > 0
  ? (validTestimonios.reduce((sum, t) => sum + parseInt(t['Calificación (1-5)'] || t.calificacion || 0), 0) / validTestimonios.length).toFixed(1)
  : 0;
const fiveStar            = testimonios.filter(t => parseInt(t['Calificación (1-5)'] || 0) === 5).length;
const authorizedToPublish = testimonios.filter(t => (t['Autoriza Publicar'] || t.autoriza || '').toLowerCase() === 'sí').length;

// ── CONTENIDO ───────────────────────────────────
const contentStats = {
  pending:   content.filter(c => (c.Status || c.status || '').toLowerCase() === 'pending').length,
  generated: content.filter(c => (c.Status || c.status || '').toLowerCase() === 'generated').length,
  approved:  content.filter(c => (c.Status || c.status || '').toLowerCase() === 'approved').length,
  published: content.filter(c => (c.Status || c.status || '').toLowerCase() === 'published').length,
  total:     content.length
};

// ── TENDENCIA SEMANAL ────────────────────────────
const now = new Date();
const oneWeekAgo  = new Date(now - 7 * 24 * 60 * 60 * 1000);
const twoWeeksAgo = new Date(now - 14 * 24 * 60 * 60 * 1000);

const parseDate = str => {
  if (!str) return new Date(0);
  const parts = str.split('/').map(Number);
  if (parts.length === 3) return new Date(parts[2], parts[1] - 1, parts[0]);
  return new Date(str);
};

const thisWeekLeads  = leads.filter(l => parseDate(l.Fecha) >= oneWeekAgo).length;
const lastWeekLeads  = leads.filter(l => { const d = parseDate(l.Fecha); return d >= twoWeeksAgo && d < oneWeekAgo; }).length;
const thisWeekPaid   = reservations.filter(r => parseDate(r.Fecha) >= oneWeekAgo && (r.Estado || '').toLowerCase() === 'paid').length;
const lastWeekPaid   = reservations.filter(r => { const d = parseDate(r.Fecha); return d >= twoWeeksAgo && d < oneWeekAgo && (r.Estado || '').toLowerCase() === 'paid'; }).length;

const updatedAt = now.toISOString();
const updatedLabel = now.toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' });

const metrics = {
  updatedAt,
  updatedLabel,
  funnel: { leads: totalLeads, demos: totalDemos, demosCompleted, reservations: totalReservations, paid },
  conversionRates: { leadToDemo, demoToReservation, reservationToPaid, overall: overallConversion },
  revenue: { estimatedUSD: revenueUSD, paidCount: paid },
  pipeline,
  agents,
  testimonials: { total: testimonios.length, avgRating: parseFloat(avgRating), fiveStar, authorizedToPublish },
  content: contentStats,
  weeklyTrend: {
    thisWeek:  { leads: thisWeekLeads, paid: thisWeekPaid },
    lastWeek:  { leads: lastWeekLeads, paid: lastWeekPaid },
    delta:     { leads: thisWeekLeads - lastWeekLeads, paid: thisWeekPaid - lastWeekPaid }
  }
};

return [{ json: metrics }];

const m = $('Calcular Métricas').first().json;
const trend = m.weeklyTrend;
const sign = n => n > 0 ? '+' + n : '' + n;

const agentRows = (m.agents || []).map(a =>
  `  ${a.name.padEnd(30)} | Demos: ${String(a.demos).padStart(3)} | Reservas: ${String(a.reservations).padStart(3)} | Testimonios: ${String(a.testimonials).padStart(3)}`
).join('\n');

const html = `
<!DOCTYPE html>
<html lang="es">
<head><meta charset="UTF-8"><style>
  body { font-family: Inter, Arial, sans-serif; background: #f4f6fb; margin: 0; padding: 24px; }
  .container { max-width: 680px; margin: 0 auto; background: #fff; border-radius: 12px; overflow: hidden; box-shadow: 0 2px 12px rgba(0,0,0,0.08); }
  .header { background: linear-gradient(135deg, #1a2744, #2563EB); padding: 28px 32px; color: #fff; }
  .header h1 { margin: 0; font-size: 20px; font-weight: 700; }
  .header p { margin: 4px 0 0; opacity: 0.7; font-size: 13px; }
  .section { padding: 20px 32px; border-bottom: 1px solid #e5e7eb; }
  .section-title { font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.8px; color: #6b7280; margin: 0 0 12px; }
  .kpi-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; }
  .kpi { background: #f8faff; border-radius: 8px; padding: 12px; text-align: center; }
  .kpi-val { font-size: 28px; font-weight: 800; color: #1e3a6e; }
  .kpi-label { font-size: 11px; color: #6b7280; margin-top: 2px; }
  .kpi-sub { font-size: 10px; color: #9ca3af; }
  .conv-row { display: flex; justify-content: space-between; padding: 6px 0; border-bottom: 1px dashed #e5e7eb; font-size: 13px; }
  .conv-label { color: #6b7280; }
  .conv-val { font-weight: 700; color: #2563EB; }
  .agent-row { display: grid; grid-template-columns: 1fr 80px 80px 80px; gap: 8px; padding: 6px 0; border-bottom: 1px solid #f3f4f6; font-size: 12px; }
  .agent-name { font-weight: 600; color: #374151; }
  .agent-num { text-align: center; color: #4F46E5; font-weight: 700; }
  .footer { padding: 16px 32px; background: #f8faff; font-size: 12px; color: #9ca3af; }
  .trend { font-size: 11px; }
  .up { color: #059669; } .down { color: #dc2626; } .flat { color: #6b7280; }
</style></head>
<body>
<div class="container">
  <div class="header">
    <h1>TUAGENTESTORE — Hub Sync Report</h1>
    <p>Actualizado: ${m.updatedLabel}</p>
  </div>

  <div class="section">
    <p class="section-title">Embudo de Conversión</p>
    <div class="kpi-grid">
      <div class="kpi"><div class="kpi-val">${m.funnel.leads}</div><div class="kpi-label">Leads</div><div class="kpi-sub">Esta semana: ${trend.thisWeek.leads} <span class="${trend.delta.leads >= 0 ? 'up' : 'down'}">(${sign(trend.delta.leads)})</span></div></div>
      <div class="kpi"><div class="kpi-val">${m.funnel.demos}</div><div class="kpi-label">Demos</div></div>
      <div class="kpi"><div class="kpi-val">${m.funnel.reservations}</div><div class="kpi-label">Reservas</div></div>
      <div class="kpi"><div class="kpi-val">${m.funnel.paid}</div><div class="kpi-label">Pagos</div><div class="kpi-sub">Esta semana: ${trend.thisWeek.paid} <span class="${trend.delta.paid >= 0 ? 'up' : 'down'}">(${sign(trend.delta.paid)})</span></div></div>
      <div class="kpi" style="background:#f0fdf4"><div class="kpi-val" style="color:#059669">$${m.revenue.estimatedUSD.toLocaleString()}</div><div class="kpi-label">Revenue Est. USD</div></div>
      <div class="kpi"><div class="kpi-val">${m.conversionRates.overall}</div><div class="kpi-label">Conv. global</div></div>
    </div>
  </div>

  <div class="section">
    <p class="section-title">Tasas de Conversión</p>
    <div class="conv-row"><span class="conv-label">Lead → Demo</span><span class="conv-val">${m.conversionRates.leadToDemo}</span></div>
    <div class="conv-row"><span class="conv-label">Demo → Reserva</span><span class="conv-val">${m.conversionRates.demoToReservation}</span></div>
    <div class="conv-row"><span class="conv-label">Reserva → Pago</span><span class="conv-val">${m.conversionRates.reservationToPaid}</span></div>
  </div>

  <div class="section">
    <p class="section-title">Pipeline — Estado de Leads</p>
    <div class="conv-row"><span class="conv-label">🆕 Nuevo</span><span class="conv-val">${m.pipeline.new}</span></div>
    <div class="conv-row"><span class="conv-label">📞 Contactado</span><span class="conv-val">${m.pipeline.contacted}</span></div>
    <div class="conv-row"><span class="conv-label">✅ Calificado</span><span class="conv-val">${m.pipeline.qualified}</span></div>
    <div class="conv-row"><span class="conv-label">🔍 Validado</span><span class="conv-val">${m.pipeline.validated}</span></div>
    <div class="conv-row"><span class="conv-label">💰 Pagado</span><span class="conv-val">${m.pipeline.paid}</span></div>
    <div class="conv-row"><span class="conv-label">❌ Cancelado</span><span class="conv-val">${m.pipeline.cancelled}</span></div>
  </div>

  <div class="section">
    <p class="section-title">Agentes — Métricas</p>
    <div class="agent-row" style="font-weight:700;color:#6b7280;font-size:11px">
      <span>Agente</span><span style="text-align:center">Demos</span><span style="text-align:center">Reservas</span><span style="text-align:center">Test.</span>
    </div>
    ${m.agents.map(a => `<div class="agent-row"><span class="agent-name">${a.name}</span><span class="agent-num">${a.demos}</span><span class="agent-num">${a.reservations}</span><span class="agent-num">${a.testimonials}</span></div>`).join('')}
  </div>

  <div class="section">
    <p class="section-title">Testimonios & NPS</p>
    <div class="conv-row"><span class="conv-label">Total testimonios</span><span class="conv-val">${m.testimonials.total}</span></div>
    <div class="conv-row"><span class="conv-label">Calificación promedio</span><span class="conv-val">${m.testimonials.avgRating} / 5 ⭐</span></div>
    <div class="conv-row"><span class="conv-label">5 estrellas</span><span class="conv-val">${m.testimonials.fiveStar}</span></div>
    <div class="conv-row"><span class="conv-label">Autorizados a publicar</span><span class="conv-val">${m.testimonials.authorizedToPublish}</span></div>
  </div>

  <div class="section">
    <p class="section-title">Calendario de Contenido</p>
    <div class="conv-row"><span class="conv-label">Pendiente</span><span class="conv-val">${m.content.pending}</span></div>
    <div class="conv-row"><span class="conv-label">Generado</span><span class="conv-val">${m.content.generated}</span></div>
    <div class="conv-row"><span class="conv-label">Aprobado</span><span class="conv-val">${m.content.approved}</span></div>
    <div class="conv-row"><span class="conv-label">Publicado</span><span class="conv-val">${m.content.published}</span></div>
  </div>

  <div class="footer">
    Ver dashboard: <a href="https://tuagentestore.com/admin/hub" style="color:#2563EB">tuagentestore.com/admin/hub</a> ·
    Panel admin: <a href="https://tuagentestore.com/admin" style="color:#2563EB">tuagentestore.com/admin</a>
  </div>
</div>
</body></html>
`;

return [{ json: { html, subject: '📊 Hub Sync Report — ' + new Date().toLocaleDateString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' }) } }];
